CREATE TABLE dim_companies (
    company_id VARCHAR,
    company_name VARCHAR,
    user_id VARCHAR
);


CREATE TABLE dim_listings_latest (
    created_at DATE,
    listing_id VARCHAR,
    country VARCHAR,
    capacity INTEGER,
    is_lux BOOLEAN,
    user_id VARCHAR
);


CREATE TABLE dim_lux_listing_id_mapping (
    listing_id VARCHAR,
    lux_listing_id VARCHAR
);


CREATE TABLE dim_users (
    ds DATE,
    ds_partitioned DATE,
    created_at DATE,
    user_id VARCHAR,
    home_state VARCHAR,
    last_profile_edit_ts TIMESTAMP,
    bio_added_ts TIMESTAMP,
    last_login_ts TIMESTAMP,
    archived_at TIMESTAMP
);


CREATE TABLE dim_users_latest (
    ds DATE,
    user_id VARCHAR,
    home_state_latest VARCHAR
);


CREATE TABLE fct_accounts (
    ds DATE,
    ds_month DATE,
    user_id VARCHAR,
    account_balance INTEGER,
    account_type VARCHAR
);


CREATE TABLE fct_bookings (
    ds DATE,
    ds_partitioned DATE,
    paid_at DATE,
    guest_id VARCHAR,
    host_id VARCHAR,
    listing_id VARCHAR,
    booking_value DOUBLE,
    is_instant BOOLEAN,
    referrer_id VARCHAR
);







CREATE TABLE fct_buys (
    ds DATE,
    ds_month DATE,
    user_id VARCHAR,
    session_id VARCHAR
);


CREATE TABLE fct_id_verifications (
    ds DATE,
    ds_partitioned DATE,
    verification_id VARCHAR,
    user_id VARCHAR,
    verification_type VARCHAR
);


CREATE TABLE fct_revenue (
    created_at DATE,
    revenue INTEGER,
    user_id VARCHAR
);


CREATE TABLE fct_views (
    ds DATE,
    ds_partitioned DATE,
    user_id VARCHAR,
    listing_id VARCHAR
);


CREATE TABLE fct_visits (
    user_id VARCHAR,
    ds DATE,
    referrer_id VARCHAR,
    session_id VARCHAR
);


